mapper.select:

SELECT id, document_id, content, doc_type, symptom_tag, chunk_index
FROM document_chunk
WHERE 1=1


        AND doc_type = #{docType}


        AND symptom_tag = #{symptomTag}


ORDER BY embedding <=> #{embedding}::vector
LIMIT #{limit}

SELECT id, document_id, content, doc_type, symptom_tag, chunk_index
FROM document_chunk
WHERE content_tsv @@ plainto_tsquery('english', #{keyword})

    AND doc_type = #{docType}


    AND symptom_tag = #{symptomTag}

ORDER BY ts_rank(content_tsv, plainto_tsquery('english', #{keyword})) DESC
LIMIT #{limit}
